svg.script:

const helicopterData = {
    'mast': {
        title: 'Mast',
        desc: 'The hollow vertical structural shaft that transfers mechanical power from the transmission to the rotor hub, driving the blades.',
        elements: ['mast-rect']
    },
    'hub': {
        title: 'Rotor Hub',
        desc: 'The complex central assembly where the rotor blades attach. It allows the blades to change pitch, flap up and down, and lead or lag during flight.',
        elements: ['hub-ellipse', 'hub-rect']
    },
    'rotor-blade': {
        title: 'Rotor Blade',
        desc: 'Aerodynamically shaped airfoils that generate the primary lift and thrust for the helicopter when spun rapidly by the engine.',
        elements: ['blade-right', 'blade-left']
    },
    'main-rotor': {
        title: 'Main Rotor System',
        desc: 'The primary lift-generating system of the aircraft, composed of the mast, hub, and all of the attached rotor blades acting together.',
        elements: ['mast-rect', 'hub-ellipse', 'hub-rect', 'blade-left', 'blade-right', 'swashplate-top', 'swashplate-bottom', 'pitch-link-1', 'pitch-link-2']
    },
    'tail-rotor': {
        title: 'Tail Rotor',
        desc: 'A smaller vertical rotor system located at the tail. It generates lateral thrust to counteract the torque of the main rotor, keeping the fuselage from spinning.',
        elements: ['tail-rotor-hub', 'tail-blade-1', 'tail-blade-2']
    },
    'fuselage': {
        title: 'Fuselage',
        desc: 'The main structural body of the helicopter that houses the cockpit, passengers, payload, and core mechanical systems.',
        elements: ['fuselage-main', 'tail-boom', 'tail-fin', 'engine-housing-base']
    },
    'cockpit': {
        title: 'Cockpit',
        desc: 'The front compartment where the pilot and crew sit. It contains all the flight controls, instruments, and avionics needed to operate the helicopter safely.',
        elements: ['window-1', 'window-2']
    },
    'landing-skids': {
        title: 'Landing Skids',
        desc: 'Simple, lightweight tubular frames that securely support the helicopter when it lands and rests on the ground, absorbing impact energy.',
        elements: ['skid-strut-1', 'skid-strut-2', 'skid-back', 'skid-main']
    },
    'tail-boom': {
        title: 'Tail Boom',
        desc: 'The long rear structure that securely connects the main fuselage to the tail rotor and vertical fin, keeping the tail rotor safely away from the main blades.',
        elements: ['tail-boom']
    },
    'engine': {
        title: 'Engine',
        desc: 'The powerplant (often a gas turbine engine) that burns fuel to generate the immense rotational power needed to spin the heavy rotors.',
        elements: ['engine-core']
    },
    'transmission': {
        title: 'Transmission (Gearbox)',
        desc: 'A heavy-duty gearbox that takes the ultra-high-speed power from the engine and drastically slows it down to turn the main and tail rotors at safe, usable speeds.',
        elements: ['transmission-box']
    },
    'swashplate': {
        title: 'Swashplate Assembly',
        desc: 'A crucial control mechanism that slides up/down and tilts to translate the pilot\'s steering commands into exact blade angle changes while they are spinning.',
        elements: ['swashplate-top', 'swashplate-bottom']
    },
    'pitch-link': {
        title: 'Pitch Link',
        desc: 'Vertical push/pull rods connecting the rotating swashplate to the rotor blades, directly twisting the blades to change their aerodynamic pitch (angle of attack).',
        elements: ['pitch-link-1', 'pitch-link-2']
    },
    'vertical-fin': {
        title: 'Vertical Fin',
        desc: 'A static vertical aerodynamic surface on the tail that acts like a weather vane, providing natural directional stability during forward flight.',
        elements: ['tail-fin']
    },
    'horizontal-stabilizer': {
        title: 'Horizontal Stabilizer',
        desc: 'Small wing-like structures mounted on the tail boom that help balance the helicopter and keep it level (pitch stability) during fast forward flight.',
        elements: ['horizontal-stab']
    },
    'intake-exhaust': {
        title: 'Air Intake / Exhaust',
        desc: 'The intake eagerly sucks in massive amounts of clean air for the turbine engine, while the exhaust forcefully expels the hot combustion gases safely away.',
        elements: ['engine-intake', 'engine-exhaust']
    }
};

function selectPart(partKey) {
    // 1. Clear previous highlights
    document.querySelectorAll('.highlight').forEach(el => el.classList.remove('highlight'));
    document.querySelectorAll('.interactive-label').forEach(el => el.classList.remove('active'));

    // 2. Get data for selected part
    const partData = helicopterData[partKey];
    if (!partData) return;

    // 3. Update the info panel text
    document.getElementById('info-title').textContent = partData.title;
    document.getElementById('info-desc').textContent = partData.desc;

    // 4. Highlight the corresponding SVG elements
    partData.elements.forEach(id => {
        const el = document.getElementById(id);
        if (el) {
            el.classList.add('highlight');
        }
    });

    // 5. Highlight the selected label
    const labelGroup = document.getElementById('group-' + partKey);
    if (labelGroup) {
        labelGroup.classList.add('active');
    }
}
